CREATE OR REPLACE FUNCTION ledger.get_balance(p_year integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_rows text[];
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
  r record;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('ledger.btn_balance_check')]);

  -- Year selector
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.link_button(pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year - 1)), (v_year - 1)::text, 'outline'),
    pgv.link_button(pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year)), v_year::text),
    pgv.link_button(pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year + 1)), (v_year + 1)::text, 'outline')
  ]);

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.code, a.label, a.type,
           coalesce(sum(el.debit), 0) AS total_debit,
           coalesce(sum(el.credit), 0) AS total_credit
      FROM ledger.account a
      LEFT JOIN ledger.entry_line el ON el.account_id = a.id
        AND EXISTS (SELECT 1 FROM ledger.journal_entry je
                     WHERE je.id = el.journal_entry_id AND je.posted = true
                       AND je.entry_date >= v_start AND je.entry_date <= v_end)
     WHERE a.active
     GROUP BY a.id, a.code, a.label, a.type
    HAVING coalesce(sum(el.debit), 0) <> 0 OR coalesce(sum(el.credit), 0) <> 0
     ORDER BY a.code
  LOOP
    v_total_debit := v_total_debit + r.total_debit;
    v_total_credit := v_total_credit + r.total_credit;
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_grand_livre', jsonb_build_object('p_account_id', (SELECT id FROM ledger.account WHERE code = r.code), 'p_year', v_year)), pgv.esc(r.code)),
      pgv.esc(r.label),
      to_char(r.total_debit, 'FM999 990.00') || ' €',
      to_char(r.total_credit, 'FM999 990.00') || ' €',
      to_char(r.total_debit - r.total_credit, 'FM999 990.00') || ' €'
    ];
  END LOOP;

  -- Stats
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('ledger.stat_total_debit'), to_char(v_total_debit, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_total_credit'), to_char(v_total_credit, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_gap'), to_char(v_total_debit - v_total_credit, 'FM999 990.00') || ' €',
      CASE WHEN v_total_debit = v_total_credit THEN pgv.t('ledger.stat_balance_ok') ELSE pgv.t('ledger.stat_imbalance') END)
  ]);

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty(pgv.t('ledger.empty_no_movement_on') || ' ' || v_year);
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('ledger.col_code'), pgv.t('ledger.col_label'), pgv.t('ledger.col_debit'), pgv.t('ledger.col_credit'), pgv.t('ledger.col_balance')],
      v_rows, 20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_balance(integer) IS 'Balance de vérification : total débit/crédit/solde par compte, avec filtres année';

CREATE OR REPLACE FUNCTION ledger.get_bilan(p_year integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_rows_r text[];
  v_rows_e text[];
  v_total_revenue numeric := 0;
  v_total_expense numeric := 0;
  v_resultat numeric;
  r record;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('ledger.nav_bilan')]);

  -- Sélecteur année
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.link_button(pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year - 1)), (v_year - 1)::text, 'outline'),
    pgv.link_button(pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year)), v_year::text),
    pgv.link_button(pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year + 1)), (v_year + 1)::text, 'outline')
  ]);

  -- Produits (revenue = classe 7)
  v_rows_r := ARRAY[]::text[];
  FOR r IN
    SELECT a.code, a.label,
           coalesce(sum(el.credit) - sum(el.debit), 0) AS balance
      FROM ledger.account a
      LEFT JOIN ledger.entry_line el ON el.account_id = a.id
        AND EXISTS (SELECT 1 FROM ledger.journal_entry je
                     WHERE je.id = el.journal_entry_id AND je.posted = true
                       AND je.entry_date >= v_start AND je.entry_date <= v_end)
     WHERE a.type = 'revenue' AND a.active
     GROUP BY a.id, a.code, a.label
     ORDER BY a.code
  LOOP
    v_total_revenue := v_total_revenue + r.balance;
    IF r.balance <> 0 THEN
      v_rows_r := v_rows_r || ARRAY[
        pgv.esc(r.code), pgv.esc(r.label),
        to_char(r.balance, 'FM999 990.00') || ' €'
      ];
    END IF;
  END LOOP;

  -- Charges (expense = classe 6)
  v_rows_e := ARRAY[]::text[];
  FOR r IN
    SELECT a.code, a.label,
           coalesce(sum(el.debit) - sum(el.credit), 0) AS balance
      FROM ledger.account a
      LEFT JOIN ledger.entry_line el ON el.account_id = a.id
        AND EXISTS (SELECT 1 FROM ledger.journal_entry je
                     WHERE je.id = el.journal_entry_id AND je.posted = true
                       AND je.entry_date >= v_start AND je.entry_date <= v_end)
     WHERE a.type = 'expense' AND a.active
     GROUP BY a.id, a.code, a.label
     ORDER BY a.code
  LOOP
    v_total_expense := v_total_expense + r.balance;
    IF r.balance <> 0 THEN
      v_rows_e := v_rows_e || ARRAY[
        pgv.esc(r.code), pgv.esc(r.label),
        to_char(r.balance, 'FM999 990.00') || ' €'
      ];
    END IF;
  END LOOP;

  v_resultat := v_total_revenue - v_total_expense;

  -- Stats résumé
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('ledger.stat_revenue'), to_char(v_total_revenue, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_expenses'), to_char(v_total_expense, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_result_net'), to_char(v_resultat, 'FM999 990.00') || ' €',
      CASE WHEN v_resultat >= 0 THEN pgv.t('ledger.stat_benefit') ELSE pgv.t('ledger.stat_deficit') END)
  ]);

  -- Tables détail
  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    pgv.t('ledger.title_revenue'),
    CASE WHEN array_length(v_rows_r, 1) IS NULL
      THEN pgv.empty(pgv.t('ledger.empty_no_revenue_on') || ' ' || v_year)
      ELSE pgv.md_table(ARRAY[pgv.t('ledger.col_code'), pgv.t('ledger.col_label'), pgv.t('ledger.col_amount')], v_rows_r)
        || '<p><strong>' || pgv.t('ledger.total_revenue') || ' : ' || to_char(v_total_revenue, 'FM999 990.00') || ' €</strong></p>'
    END,
    pgv.t('ledger.title_expenses'),
    CASE WHEN array_length(v_rows_e, 1) IS NULL
      THEN pgv.empty(pgv.t('ledger.empty_no_expense_on') || ' ' || v_year)
      ELSE pgv.md_table(ARRAY[pgv.t('ledger.col_code'), pgv.t('ledger.col_label'), pgv.t('ledger.col_amount')], v_rows_e)
        || '<p><strong>' || pgv.t('ledger.total_expenses') || ' : ' || to_char(v_total_expense, 'FM999 990.00') || ' €</strong></p>'
    END
  ]);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_bilan(integer) IS 'Bilan P&L : produits vs charges par compte, résultat net. Filtre par année.';

CREATE OR REPLACE FUNCTION ledger.get_entries()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.id, je.entry_date, je.reference, je.description, je.posted,
           coalesce(sum(el.debit), 0) AS total_debit
      FROM ledger.journal_entry je
      LEFT JOIN ledger.entry_line el ON el.journal_entry_id = je.id
     GROUP BY je.id
     ORDER BY je.entry_date DESC, je.id DESC
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.description),
      to_char(r.total_debit, 'FM999 990.00') || ' €',
      CASE WHEN r.posted THEN pgv.badge(pgv.t('ledger.badge_posted'), 'success') ELSE pgv.badge(pgv.t('ledger.badge_draft'), 'warning') END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty(pgv.t('ledger.empty_no_entry'), pgv.t('ledger.empty_first_entry_accounting'));
  ELSE
    v_body := pgv.md_table(
      ARRAY[pgv.t('ledger.col_date'), pgv.t('ledger.col_reference'), pgv.t('ledger.col_description'), pgv.t('ledger.col_amount'), pgv.t('ledger.col_status')],
      v_rows, 15
    );
  END IF;

  v_body := v_body || '<p>' || pgv.form_dialog(
    'dlg-new-entry',
    pgv.t('ledger.title_new_entry'),
    pgv.input('entry_date', 'date', pgv.t('ledger.field_date'), to_char(CURRENT_DATE, 'YYYY-MM-DD'), true)
    || pgv.input('reference', 'text', pgv.t('ledger.field_reference'), '', true)
    || pgv.input('description', 'text', pgv.t('ledger.field_description'), '', true),
    'post_entry_save',
    pgv.t('ledger.btn_new_entry')
  ) || '</p>';

  RETURN pgv.breadcrumb(VARIADIC ARRAY[pgv.t('ledger.nav_entries')]) || v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entries() IS 'Journal des écritures : table paginée avec statut';

CREATE OR REPLACE FUNCTION ledger.get_entry(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry record;
  v_body text;
  v_rows text[];
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
  v_balanced boolean;
  v_accounts_json jsonb;
  r record;
BEGIN
  SELECT * INTO v_entry FROM ledger.journal_entry WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty(pgv.t('ledger.empty_entry_not_found')); END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    pgv.t('ledger.nav_entries'), pgv.call_ref('get_entries'),
    v_entry.reference
  ]);

  v_body := v_body || pgv.dl(VARIADIC ARRAY[
    pgv.t('ledger.col_date'), to_char(v_entry.entry_date, 'DD/MM/YYYY'),
    pgv.t('ledger.col_reference'), pgv.esc(v_entry.reference),
    pgv.t('ledger.col_description'), pgv.esc(v_entry.description),
    pgv.t('ledger.col_status'), CASE WHEN v_entry.posted THEN pgv.badge(pgv.t('ledger.badge_posted'), 'success') ELSE pgv.badge(pgv.t('ledger.badge_draft'), 'warning') END
  ]);

  -- Lignes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT el.id, el.account_id, a.code, a.label AS account_label,
           el.debit, el.credit, el.label
      FROM ledger.entry_line el
      JOIN ledger.account a ON a.id = el.account_id
     WHERE el.journal_entry_id = p_id
     ORDER BY el.id
  LOOP
    v_total_debit := v_total_debit + r.debit;
    v_total_credit := v_total_credit + r.credit;
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a> %s', pgv.call_ref('get_account', jsonb_build_object('p_id', r.account_id)), pgv.esc(r.code), pgv.esc(r.account_label)),
      pgv.esc(r.label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END,
      CASE WHEN NOT v_entry.posted
        THEN pgv.action('post_line_delete', pgv.t('ledger.btn_delete_short'), jsonb_build_object('id', r.id, 'entry_id', p_id), pgv.t('ledger.confirm_delete_line'), 'danger')
        ELSE ''
      END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty(pgv.t('ledger.empty_no_line'), pgv.t('ledger.empty_add_lines'));
  ELSE
    -- Add totals row
    v_rows := v_rows || ARRAY[
      '<strong>' || pgv.t('ledger.title_total') || '</strong>', '',
      '<strong>' || to_char(v_total_debit, 'FM999 990.00') || '</strong>',
      '<strong>' || to_char(v_total_credit, 'FM999 990.00') || '</strong>',
      ''
    ];
    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('ledger.col_account'), pgv.t('ledger.col_label'), pgv.t('ledger.col_debit'), pgv.t('ledger.col_credit'), ''],
      v_rows
    );
  END IF;

  -- Alert si déséquilibrée
  v_balanced := ledger._entry_balanced(p_id);
  IF NOT v_balanced AND v_total_debit + v_total_credit > 0 THEN
    v_body := v_body || pgv.alert(
      pgv.t('ledger.err_unbalanced_prefix') || ' ' || to_char(v_total_debit, 'FM999 990.00')
        || E' \u20ac \u2260 ' || pgv.t('ledger.col_credit') || ' ' || to_char(v_total_credit, 'FM999 990.00') || E' \u20ac',
      'danger'
    );
  END IF;

  -- Formulaire ajout ligne (brouillon uniquement)
  IF NOT v_entry.posted THEN
    -- Build account options
    v_accounts_json := '[]'::jsonb;
    FOR r IN SELECT id, code, label FROM ledger.account WHERE active ORDER BY code LOOP
      v_accounts_json := v_accounts_json || jsonb_build_array(jsonb_build_object('value', r.id::text, 'label', r.code || E' \u2014 ' || r.label));
    END LOOP;

    -- Actions brouillon
    v_body := v_body || pgv.grid(VARIADIC ARRAY[
      pgv.form_dialog(
        'dlg-add-line',
        pgv.t('ledger.title_add_line'),
        '<input type="hidden" name="entry_id" value="' || p_id || '">'
        || pgv.sel('account_id', pgv.t('ledger.field_account'), v_accounts_json)
        || pgv.grid(VARIADIC ARRAY[
          pgv.input('debit', 'number', pgv.t('ledger.field_debit'), '0'),
          pgv.input('credit', 'number', pgv.t('ledger.field_credit'), '0')
        ])
        || pgv.input('label', 'text', pgv.t('ledger.field_label'), ''),
        'post_line_add',
        pgv.t('ledger.btn_add')),
      pgv.form_dialog(
        'dlg-edit-' || p_id,
        pgv.t('ledger.btn_edit') || ' ' || pgv.esc(v_entry.reference),
        '<input type="hidden" name="id" value="' || p_id || '">'
        || pgv.input('entry_date', 'date', pgv.t('ledger.field_date'), to_char(v_entry.entry_date, 'YYYY-MM-DD'), true)
        || pgv.input('reference', 'text', pgv.t('ledger.field_reference'), pgv.esc(v_entry.reference), true)
        || pgv.input('description', 'text', pgv.t('ledger.field_description'), pgv.esc(v_entry.description), true),
        'post_entry_save',
        pgv.t('ledger.btn_edit'),
        'outline'),
      pgv.action('post_entry_post', pgv.t('ledger.btn_post'), jsonb_build_object('id', p_id), pgv.t('ledger.confirm_post_entry')),
      pgv.action('post_entry_delete', pgv.t('ledger.btn_delete'), jsonb_build_object('id', p_id), pgv.t('ledger.confirm_delete_draft'), 'danger')
    ]);
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entry(integer) IS 'Fiche écriture : détail + lignes + formulaire ajout ligne si brouillon';

CREATE OR REPLACE FUNCTION ledger.get_entry_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry record;
  v_body text;
  v_title text;
  v_date text;
  v_ref text;
  v_desc text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_entry FROM ledger.journal_entry WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty(pgv.t('ledger.empty_entry_not_found')); END IF;
    IF v_entry.posted THEN RETURN pgv.alert(pgv.t('ledger.err_posted_readonly'), 'danger'); END IF;
    v_title := pgv.t('ledger.btn_edit') || ' ' || v_entry.reference;
    v_date := to_char(v_entry.entry_date, 'YYYY-MM-DD');
    v_ref := pgv.esc(v_entry.reference);
    v_desc := pgv.esc(v_entry.description);
  ELSE
    v_title := pgv.t('ledger.title_new_entry');
    v_date := to_char(CURRENT_DATE, 'YYYY-MM-DD');
    v_ref := '';
    v_desc := '';
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    pgv.t('ledger.nav_entries'), pgv.call_ref('get_entries'),
    v_title
  ]);

  v_body := v_body || pgv.form('post_entry_save',
    CASE WHEN p_id IS NOT NULL THEN '<input type="hidden" name="id" value="' || p_id || '">' ELSE '' END
    || pgv.input('entry_date', 'date', pgv.t('ledger.field_date'), v_date, true)
    || pgv.input('reference', 'text', pgv.t('ledger.field_reference'), v_ref, true)
    || pgv.input('description', 'text', pgv.t('ledger.field_description'), v_desc, true),
    pgv.t('ledger.btn_save'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entry_form(integer) IS 'Formulaire création/édition écriture comptable';

CREATE OR REPLACE FUNCTION ledger.get_exercice(p_year integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_exercice record;
  v_total_revenue numeric;
  v_total_expense numeric;
  v_resultat numeric;
  v_entry_count integer;
  v_draft_count integer;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('ledger.nav_exercice') || ' ' || v_year]);

  -- Year selector
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.link_button(pgv.call_ref('get_exercice', jsonb_build_object('p_year', v_year - 1)), (v_year - 1)::text, 'outline'),
    pgv.link_button(pgv.call_ref('get_exercice', jsonb_build_object('p_year', v_year)), v_year::text),
    pgv.link_button(pgv.call_ref('get_exercice', jsonb_build_object('p_year', v_year + 1)), (v_year + 1)::text, 'outline')
  ]);

  -- Exercice status
  SELECT * INTO v_exercice FROM ledger.exercice WHERE year = v_year;

  -- Compute totals from posted entries
  SELECT coalesce(sum(CASE WHEN a.type = 'revenue' THEN el.credit - el.debit ELSE 0 END), 0),
         coalesce(sum(CASE WHEN a.type = 'expense' THEN el.debit - el.credit ELSE 0 END), 0)
    INTO v_total_revenue, v_total_expense
    FROM ledger.entry_line el
    JOIN ledger.account a ON a.id = el.account_id
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  v_resultat := v_total_revenue - v_total_expense;

  SELECT count(*), count(*) FILTER (WHERE NOT posted)
    INTO v_entry_count, v_draft_count
    FROM ledger.journal_entry
   WHERE entry_date >= v_start AND entry_date <= v_end;

  -- Stats
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('ledger.stat_status'),
      CASE WHEN v_exercice.closed THEN pgv.badge(pgv.t('ledger.badge_closed'), 'success')
           ELSE pgv.badge(pgv.t('ledger.badge_open'), 'warning') END),
    pgv.stat(pgv.t('ledger.stat_revenue'), to_char(v_total_revenue, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_expenses'), to_char(v_total_expense, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_result'), to_char(v_resultat, 'FM999 990.00') || ' €',
      CASE WHEN v_resultat >= 0 THEN pgv.t('ledger.stat_benefit') ELSE pgv.t('ledger.stat_deficit') END)
  ]);

  -- Entries summary
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('ledger.stat_entries'), v_entry_count::text),
    pgv.stat(pgv.t('ledger.stat_drafts'), v_draft_count::text,
      CASE WHEN v_draft_count > 0 THEN pgv.t('ledger.stat_drafts_hint') ELSE NULL END)
  ]);

  -- Links
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.link_button(pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year)), pgv.t('ledger.btn_balance_check'), 'outline'),
    pgv.link_button(pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year)), pgv.t('ledger.btn_bilan_pl'), 'outline')
  ]);

  -- Clôture action
  IF NOT coalesce(v_exercice.closed, false) THEN
    v_body := v_body || pgv.action(
      'post_cloture',
      pgv.t('ledger.btn_close_exercice') || ' ' || v_year,
      jsonb_build_object('year', v_year),
      pgv.t('ledger.confirm_close_exercice') || ' ' || v_year || ' ' || pgv.t('ledger.confirm_close_suffix')
    );
  ELSE
    v_body := v_body || '<p>' || pgv.t('ledger.closed_on') || ' '
      || to_char(v_exercice.closed_at, 'DD/MM/YYYY à HH24:MI')
      || ' — ' || pgv.t('ledger.result_recorded') || ' : ' || to_char(v_exercice.result, 'FM999 990.00') || ' €</p>';
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_exercice(integer) IS 'Vue synthétique exercice : produits, charges, résultat, statut (ouvert/clos), action clôture';

CREATE OR REPLACE FUNCTION ledger.get_grand_livre(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_account_id integer;
  v_account record;
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_rows text[];
  v_cumul numeric := 0;
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
  r record;
BEGIN
  v_account_id := (p_params->>'p_account_id')::integer;
  IF v_account_id IS NULL THEN RAISE EXCEPTION 'p_account_id requis'; END IF;

  SELECT * INTO v_account FROM ledger.account WHERE id = v_account_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Compte % introuvable', v_account_id; END IF;

  v_year := coalesce((p_params->>'p_year')::integer, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    pgv.t('ledger.nav_balance'), pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year)),
    v_account.code || ' — ' || v_account.label
  ]);

  -- Year selector
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.link_button(pgv.call_ref('get_grand_livre', jsonb_build_object('p_account_id', v_account_id, 'p_year', v_year - 1)), (v_year - 1)::text, 'outline'),
    pgv.link_button(pgv.call_ref('get_grand_livre', jsonb_build_object('p_account_id', v_account_id, 'p_year', v_year)), v_year::text),
    pgv.link_button(pgv.call_ref('get_grand_livre', jsonb_build_object('p_account_id', v_account_id, 'p_year', v_year + 1)), (v_year + 1)::text, 'outline')
  ]);

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.id AS entry_id, je.entry_date, je.reference, el.label,
           el.debit, el.credit
      FROM ledger.entry_line el
      JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
     WHERE el.account_id = v_account_id
       AND je.posted = true
       AND je.entry_date >= v_start AND je.entry_date <= v_end
     ORDER BY je.entry_date, je.id
  LOOP
    v_cumul := v_cumul + r.debit - r.credit;
    v_total_debit := v_total_debit + r.debit;
    v_total_credit := v_total_credit + r.credit;
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.entry_id)), pgv.esc(r.reference)),
      pgv.esc(r.label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END,
      to_char(v_cumul, 'FM999 990.00')
    ];
  END LOOP;

  -- Stats
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('ledger.stat_total_debit'), to_char(v_total_debit, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_total_credit'), to_char(v_total_credit, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_balance'), to_char(v_cumul, 'FM999 990.00') || ' €')
  ]);

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty(pgv.t('ledger.empty_no_movement_on') || ' ' || v_year, pgv.t('ledger.empty_no_posted_period'));
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('ledger.col_date'), pgv.t('ledger.col_reference'), pgv.t('ledger.col_label'), pgv.t('ledger.col_debit'), pgv.t('ledger.col_credit'), pgv.t('ledger.col_cumulative')],
      v_rows, 20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_grand_livre(jsonb) IS 'Grand livre : détail des écritures d''un compte avec solde cumulé, filtre par année';

CREATE OR REPLACE FUNCTION ledger.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_solde_banque numeric;
  v_ca_mois numeric;
  v_charges_mois numeric;
  v_resultat numeric;
  v_month_start date;
  v_month_end date;
  v_rows text[];
  r record;
BEGIN
  v_month_start := date_trunc('month', CURRENT_DATE)::date;
  v_month_end := (date_trunc('month', CURRENT_DATE) + interval '1 month' - interval '1 day')::date;

  -- KPIs
  SELECT ledger._account_balance(a.id) INTO v_solde_banque
    FROM ledger.account a WHERE a.code = '512';

  v_ca_mois := ledger._period_total('revenue', v_month_start, v_month_end);
  v_charges_mois := ledger._period_total('expense', v_month_start, v_month_end);
  v_resultat := coalesce(v_ca_mois, 0) - coalesce(v_charges_mois, 0);

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('ledger.stat_bank_balance'), to_char(coalesce(v_solde_banque, 0), 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_monthly_revenue'), to_char(coalesce(v_ca_mois, 0), 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_monthly_expenses'), to_char(coalesce(v_charges_mois, 0), 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_result'), to_char(v_resultat, 'FM999 990.00') || ' €')
  ]);

  -- Écritures récentes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.id, je.entry_date, je.reference, je.description, je.posted,
           coalesce(sum(el.debit), 0) AS total_debit
      FROM ledger.journal_entry je
      LEFT JOIN ledger.entry_line el ON el.journal_entry_id = je.id
     GROUP BY je.id
     ORDER BY je.entry_date DESC, je.id DESC
     LIMIT 10
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.description),
      to_char(r.total_debit, 'FM999 990.00') || ' €',
      CASE WHEN r.posted THEN pgv.badge(pgv.t('ledger.badge_posted'), 'success') ELSE pgv.badge(pgv.t('ledger.badge_draft'), 'warning') END
    ];
  END LOOP;

  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    pgv.t('ledger.title_recent_entries'),
    CASE WHEN array_length(v_rows, 1) IS NULL
      THEN pgv.empty(pgv.t('ledger.empty_no_entry'), pgv.t('ledger.empty_first_entry'))
      ELSE pgv.md_table(ARRAY[pgv.t('ledger.col_date'), pgv.t('ledger.col_reference'), pgv.t('ledger.col_description'), pgv.t('ledger.col_amount'), pgv.t('ledger.col_status')], v_rows)
    END
  ]);

  v_body := v_body || '<p>' || pgv.form_dialog(
    'dlg-new-entry',
    pgv.t('ledger.title_new_entry'),
    pgv.input('entry_date', 'date', pgv.t('ledger.field_date'), to_char(CURRENT_DATE, 'YYYY-MM-DD'), true)
    || pgv.input('reference', 'text', pgv.t('ledger.field_reference'), '', true)
    || pgv.input('description', 'text', pgv.t('ledger.field_description'), '', true),
    'post_entry_save',
    pgv.t('ledger.btn_new_entry')
  ) || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_index() IS 'Dashboard comptabilité : KPIs (banque, CA, charges, résultat) + écritures récentes';

CREATE OR REPLACE FUNCTION ledger.get_tva(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_quarter integer;
  v_start date;
  v_end date;
  v_collectee numeric;
  v_deductible numeric;
  v_solde numeric;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_year := coalesce((p_params->>'p_year')::integer, extract(year FROM CURRENT_DATE)::integer);
  v_quarter := coalesce((p_params->>'p_quarter')::integer, extract(quarter FROM CURRENT_DATE)::integer);

  v_start := make_date(v_year, (v_quarter - 1) * 3 + 1, 1);
  v_end := (v_start + interval '3 months' - interval '1 day')::date;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('ledger.nav_tva')]);

  -- Sélecteur période
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.link_button(pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 1)), 'T1', 'outline'),
    pgv.link_button(pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 2)), 'T2', 'outline'),
    pgv.link_button(pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 3)), 'T3', 'outline'),
    pgv.link_button(pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 4)), 'T4', 'outline')
  ]);

  v_body := v_body || '<p>' || pgv.t('ledger.title_period') || ' : T' || v_quarter || ' ' || v_year
    || ' (' || to_char(v_start, 'DD/MM/YYYY') || ' — ' || to_char(v_end, 'DD/MM/YYYY') || ')</p>';

  -- TVA collectée (4457)
  SELECT coalesce(sum(el.credit) - sum(el.debit), 0) INTO v_collectee
    FROM ledger.entry_line el
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
    JOIN ledger.account a ON a.id = el.account_id
   WHERE a.code = '4457' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  -- TVA déductible (4456)
  SELECT coalesce(sum(el.debit) - sum(el.credit), 0) INTO v_deductible
    FROM ledger.entry_line el
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
    JOIN ledger.account a ON a.id = el.account_id
   WHERE a.code = '4456' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  v_solde := v_collectee - v_deductible;

  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('ledger.stat_tva_collected'), to_char(v_collectee, 'FM999 990.00') || ' €'),
    pgv.stat(pgv.t('ledger.stat_tva_deductible'), to_char(v_deductible, 'FM999 990.00') || ' €'),
    pgv.stat(
      CASE WHEN v_solde >= 0 THEN pgv.t('ledger.stat_tva_due') ELSE pgv.t('ledger.stat_tva_credit') END,
      to_char(abs(v_solde), 'FM999 990.00') || ' €'
    )
  ]);

  -- Détail par écriture
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.entry_date, je.reference, je.id AS entry_id,
           el.debit, el.credit, a.code, a.label AS account_label
      FROM ledger.entry_line el
      JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
      JOIN ledger.account a ON a.id = el.account_id
     WHERE a.code IN ('4456', '4457') AND je.posted = true
       AND je.entry_date >= v_start AND je.entry_date <= v_end
     ORDER BY je.entry_date, je.id
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.entry_id)), pgv.esc(r.reference)),
      r.code || ' ' || pgv.esc(r.account_label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h4>' || pgv.t('ledger.title_tva_detail') || '</h4>'
      || pgv.md_table(ARRAY[pgv.t('ledger.col_date'), pgv.t('ledger.col_reference'), pgv.t('ledger.col_account'), pgv.t('ledger.col_debit'), pgv.t('ledger.col_credit')], v_rows);
  ELSE
    v_body := v_body || pgv.empty(pgv.t('ledger.empty_no_tva'));
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_tva(jsonb) IS 'Déclaration TVA : collectée, déductible, solde. Filtre par trimestre/année.';

