CREATE OR REPLACE FUNCTION ledger.post_cloture(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_total_revenue numeric;
  v_total_expense numeric;
  v_resultat numeric;
  v_draft_count integer;
  v_entry_id integer;
  v_account_120 integer;
BEGIN
  v_year := (p_data->>'year')::integer;
  IF v_year IS NULL THEN RAISE EXCEPTION 'Année requise'; END IF;

  -- Guard: pas de double clôture
  IF EXISTS (SELECT 1 FROM ledger.exercice WHERE year = v_year AND closed = true) THEN
    RETURN pgv.toast(pgv.t('ledger.nav_exercice') || ' ' || v_year || ' ' || pgv.t('ledger.err_already_closed'), 'error');
  END IF;

  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  -- Guard: pas d'écritures brouillon sur la période
  SELECT count(*) INTO v_draft_count
    FROM ledger.journal_entry
   WHERE posted = false
     AND entry_date >= v_start AND entry_date <= v_end;

  IF v_draft_count > 0 THEN
    RETURN pgv.toast(v_draft_count || ' ' || pgv.t('ledger.err_drafts_remaining'), 'error');
  END IF;

  -- Calcul résultat : produits - charges (écritures postées)
  SELECT coalesce(sum(CASE WHEN a.type = 'revenue' THEN el.credit - el.debit ELSE 0 END), 0),
         coalesce(sum(CASE WHEN a.type = 'expense' THEN el.debit - el.credit ELSE 0 END), 0)
    INTO v_total_revenue, v_total_expense
    FROM ledger.entry_line el
    JOIN ledger.account a ON a.id = el.account_id
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  v_resultat := v_total_revenue - v_total_expense;

  -- Écriture de résultat (compte 120)
  SELECT id INTO v_account_120 FROM ledger.account WHERE code = '120';
  IF v_account_120 IS NULL THEN RAISE EXCEPTION 'Compte 120 (Résultat) introuvable dans le plan comptable'; END IF;

  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES (v_end, 'CLO-' || v_year, 'Clôture exercice ' || v_year || ' — résultat ' || to_char(v_resultat, 'FM999 990.00') || ' €')
  RETURNING id INTO v_entry_id;

  -- Zero out revenue accounts
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  SELECT v_entry_id, a.id, coalesce(sum(el.credit - el.debit), 0), 0, 'Solde ' || a.label
    FROM ledger.account a
    JOIN ledger.entry_line el ON el.account_id = a.id
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE a.type = 'revenue' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end
     AND je.id <> v_entry_id
   GROUP BY a.id, a.label
  HAVING coalesce(sum(el.credit - el.debit), 0) <> 0;

  -- Zero out expense accounts
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  SELECT v_entry_id, a.id, 0, coalesce(sum(el.debit - el.credit), 0), 'Solde ' || a.label
    FROM ledger.account a
    JOIN ledger.entry_line el ON el.account_id = a.id
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE a.type = 'expense' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end
     AND je.id <> v_entry_id
   GROUP BY a.id, a.label
  HAVING coalesce(sum(el.debit - el.credit), 0) <> 0;

  -- Result to account 120
  IF v_resultat >= 0 THEN
    INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (v_entry_id, v_account_120, 0, v_resultat, 'Résultat bénéficiaire ' || v_year);
  ELSE
    INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (v_entry_id, v_account_120, abs(v_resultat), 0, 'Résultat déficitaire ' || v_year);
  END IF;

  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  INSERT INTO ledger.exercice (year, closed, closed_at, result)
  VALUES (v_year, true, now(), v_resultat)
  ON CONFLICT ON CONSTRAINT exercice_tenant_year_key
  DO UPDATE SET closed = true, closed_at = now(), result = v_resultat;

  RETURN pgv.toast(pgv.t('ledger.toast_exercice_closed') || ' ' || v_year || ' — ' || pgv.t('ledger.stat_result') || ' : ' || to_char(v_resultat, 'FM999 990.00') || ' €')
    || pgv.redirect(pgv.call_ref('get_exercice', jsonb_build_object('p_year', v_year)));
END;
$function$;
COMMENT ON FUNCTION ledger.post_cloture(jsonb) IS 'Clôture d''exercice : vérifie écritures postées, calcule résultat, crée écriture de résultat (120), marque exercice clos';

CREATE OR REPLACE FUNCTION ledger.post_entry_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id integer;
BEGIN
  v_id := (p_data->>'id')::integer;

  IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_id AND NOT posted) THEN
    RAISE EXCEPTION 'Écriture introuvable ou déjà validée — suppression impossible';
  END IF;

  DELETE FROM ledger.journal_entry WHERE id = v_id;

  RETURN pgv.toast(pgv.t('ledger.toast_entry_deleted'))
    || pgv.redirect(pgv.call_ref('get_entries'));
END;
$function$;
COMMENT ON FUNCTION ledger.post_entry_delete(jsonb) IS 'Supprimer une écriture brouillon. RAISE si validée.';

CREATE OR REPLACE FUNCTION ledger.post_entry_post(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id integer;
BEGIN
  v_id := (p_data->>'id')::integer;

  IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_id AND NOT posted) THEN
    RAISE EXCEPTION 'Écriture introuvable ou déjà validée';
  END IF;

  IF NOT ledger._entry_balanced(v_id) THEN
    RAISE EXCEPTION 'Écriture déséquilibrée : impossible de valider';
  END IF;

  UPDATE ledger.journal_entry SET posted = true WHERE id = v_id;

  RETURN pgv.toast(pgv.t('ledger.toast_entry_posted'))
    || pgv.redirect(pgv.call_ref('get_entry', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION ledger.post_entry_post(jsonb) IS 'Valider une écriture brouillon (posted=true). RAISE si déséquilibrée.';

CREATE OR REPLACE FUNCTION ledger.post_entry_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id integer;
BEGIN
  IF p_data->>'id' IS NOT NULL THEN
    v_id := (p_data->>'id')::integer;
    IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_id AND NOT posted) THEN
      RAISE EXCEPTION 'Seuls les brouillons sont modifiables';
    END IF;
    UPDATE ledger.journal_entry SET
      entry_date = (p_data->>'entry_date')::date,
      reference = p_data->>'reference',
      description = p_data->>'description'
    WHERE id = v_id;
  ELSE
    INSERT INTO ledger.journal_entry (entry_date, reference, description)
    VALUES (
      coalesce((p_data->>'entry_date')::date, CURRENT_DATE),
      p_data->>'reference',
      p_data->>'description'
    ) RETURNING id INTO v_id;
  END IF;

  RETURN pgv.toast(pgv.t('ledger.toast_entry_saved'))
    || pgv.redirect(pgv.call_ref('get_entry', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION ledger.post_entry_save(jsonb) IS 'Créer ou modifier une écriture brouillon (upsert)';

CREATE OR REPLACE FUNCTION ledger.post_from_expense(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_note_id integer;
  v_montant_ht numeric(12,2);
  v_tva numeric(12,2);
  v_montant_ttc numeric(12,2);
  v_code_comptable text;
  v_libelle text;
  v_entry_id integer;
  v_account_charge integer;
  v_account_4456 integer;
  v_account_421 integer;
BEGIN
  v_note_id := (p_data->>'note_id')::integer;
  v_montant_ht := (p_data->>'montant_ht')::numeric;
  v_tva := coalesce((p_data->>'tva')::numeric, 0);
  v_code_comptable := coalesce(p_data->>'code_comptable', '625');
  v_libelle := coalesce(p_data->>'libelle', 'Note de frais #' || v_note_id);

  IF v_note_id IS NULL THEN RAISE EXCEPTION 'note_id requis'; END IF;
  IF v_montant_ht IS NULL OR v_montant_ht <= 0 THEN RAISE EXCEPTION 'montant_ht requis et > 0'; END IF;

  v_montant_ttc := v_montant_ht + v_tva;

  -- Guard: doublon interdit
  IF EXISTS (SELECT 1 FROM ledger.journal_entry WHERE expense_note_id = v_note_id) THEN
    RETURN pgv.toast(pgv.t('ledger.err_duplicate_expense'), 'error');
  END IF;

  -- Resolve account IDs
  SELECT id INTO v_account_charge FROM ledger.account WHERE code = v_code_comptable;
  IF v_account_charge IS NULL THEN RAISE EXCEPTION 'Compte % introuvable dans le plan comptable', v_code_comptable; END IF;

  SELECT id INTO v_account_4456 FROM ledger.account WHERE code = '4456';
  SELECT id INTO v_account_421 FROM ledger.account WHERE code = '421';

  IF v_account_421 IS NULL THEN RAISE EXCEPTION 'Compte 421 Personnel introuvable'; END IF;

  -- Create journal entry
  INSERT INTO ledger.journal_entry (entry_date, reference, description, expense_note_id)
  VALUES (
    CURRENT_DATE,
    'NDF-' || v_note_id,
    v_libelle,
    v_note_id
  ) RETURNING id INTO v_entry_id;

  -- 6xx Charge — débit HT
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES (v_entry_id, v_account_charge, v_montant_ht, 0, v_libelle);

  -- 4456 TVA déductible — débit TVA (si > 0)
  IF v_tva > 0 THEN
    INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (v_entry_id, v_account_4456, v_tva, 0, 'TVA déductible NDF-' || v_note_id);
  END IF;

  -- 421 Personnel — crédit TTC (dette envers le salarié)
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES (v_entry_id, v_account_421, 0, v_montant_ttc, 'Remboursement NDF-' || v_note_id);

  RETURN pgv.toast(pgv.t('ledger.toast_entry_from_expense') || ' — ' || pgv.esc(v_libelle))
    || pgv.redirect(pgv.call_ref('get_entry', jsonb_build_object('p_id', v_entry_id)));
END;
$function$;
COMMENT ON FUNCTION ledger.post_from_expense(jsonb) IS 'Créer écriture comptable de remboursement note de frais (6xx/4456/421)';

CREATE OR REPLACE FUNCTION ledger.post_from_facture(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_facture_id integer;
  v_facture record;
  v_entry_id integer;
  v_total_ht numeric(12,2);
  v_total_tva numeric(12,2);
  v_total_ttc numeric(12,2);
  v_account_411 integer;
  v_account_4457 integer;
  v_account_706 integer;
BEGIN
  v_facture_id := (p_data->>'facture_id')::integer;

  SELECT * INTO v_facture FROM quote.facture WHERE id = v_facture_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Facture % introuvable', v_facture_id; END IF;

  -- Guard: doublon interdit
  IF EXISTS (SELECT 1 FROM ledger.journal_entry WHERE facture_id = v_facture_id) THEN
    RETURN pgv.toast(pgv.t('ledger.err_duplicate_facture'), 'error');
  END IF;

  -- Totaux
  SELECT coalesce(sum(round(l.quantite * l.prix_unitaire, 2)), 0),
         coalesce(sum(round(l.quantite * l.prix_unitaire * l.tva_rate / 100, 2)), 0)
    INTO v_total_ht, v_total_tva
    FROM quote.ligne l
   WHERE l.facture_id = v_facture_id;

  v_total_ttc := v_total_ht + v_total_tva;

  IF v_total_ttc = 0 THEN RAISE EXCEPTION 'Facture sans montant'; END IF;

  -- Resolve account IDs
  SELECT id INTO v_account_411 FROM ledger.account WHERE code = '411';
  SELECT id INTO v_account_4457 FROM ledger.account WHERE code = '4457';
  SELECT id INTO v_account_706 FROM ledger.account WHERE code = '706';

  -- Create journal entry with facture_id
  INSERT INTO ledger.journal_entry (entry_date, reference, description, facture_id)
  VALUES (
    coalesce(v_facture.paid_at::date, CURRENT_DATE),
    'FAC-' || v_facture.numero,
    'Facture ' || v_facture.numero || ' — ' || v_facture.objet,
    v_facture_id
  ) RETURNING id INTO v_entry_id;

  -- 411 Clients — débit TTC
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES (v_entry_id, v_account_411, v_total_ttc, 0, 'Client facture ' || v_facture.numero);

  -- 4457 TVA collectée — crédit TVA
  IF v_total_tva > 0 THEN
    INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (v_entry_id, v_account_4457, 0, v_total_tva, 'TVA collectée facture ' || v_facture.numero);
  END IF;

  -- 706 Prestations — crédit HT
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES (v_entry_id, v_account_706, 0, v_total_ht, 'Prestation facture ' || v_facture.numero);

  RETURN pgv.toast(pgv.t('ledger.toast_entry_from_facture') || ' ' || pgv.esc(v_facture.numero))
    || pgv.redirect(pgv.call_ref('get_entry', jsonb_build_object('p_id', v_entry_id)));
END;
$function$;
COMMENT ON FUNCTION ledger.post_from_facture(jsonb) IS 'Créer écriture comptable de vente depuis une facture quote (411/4457/706-707)';

CREATE OR REPLACE FUNCTION ledger.post_line_add(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_account_id integer;
  v_debit numeric(12,2);
  v_credit numeric(12,2);
BEGIN
  v_entry_id := (p_data->>'entry_id')::integer;

  IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_entry_id AND NOT posted) THEN
    RAISE EXCEPTION 'Écriture introuvable ou déjà validée';
  END IF;

  -- Resolve account by id or code
  IF p_data->>'account_id' IS NOT NULL THEN
    v_account_id := (p_data->>'account_id')::integer;
  ELSIF p_data->>'account_code' IS NOT NULL THEN
    SELECT id INTO v_account_id FROM ledger.account WHERE code = p_data->>'account_code';
    IF NOT FOUND THEN RAISE EXCEPTION 'Compte % introuvable', p_data->>'account_code'; END IF;
  ELSE
    RAISE EXCEPTION 'account_id ou account_code requis';
  END IF;

  v_debit := coalesce((p_data->>'debit')::numeric, 0);
  v_credit := coalesce((p_data->>'credit')::numeric, 0);

  IF v_debit = 0 AND v_credit = 0 THEN
    RAISE EXCEPTION 'Débit ou crédit doit être > 0';
  END IF;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES (v_entry_id, v_account_id, v_debit, v_credit, coalesce(p_data->>'label', ''));

  RETURN pgv.toast(pgv.t('ledger.toast_line_added'))
    || pgv.redirect(pgv.call_ref('get_entry', jsonb_build_object('p_id', v_entry_id)));
END;
$function$;
COMMENT ON FUNCTION ledger.post_line_add(jsonb) IS 'Ajouter une ligne à une écriture brouillon';

CREATE OR REPLACE FUNCTION ledger.post_line_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id integer;
  v_entry_id integer;
BEGIN
  v_id := (p_data->>'id')::integer;
  v_entry_id := (p_data->>'entry_id')::integer;

  IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_entry_id AND NOT posted) THEN
    RAISE EXCEPTION 'Écriture introuvable ou déjà validée';
  END IF;

  DELETE FROM ledger.entry_line WHERE id = v_id AND journal_entry_id = v_entry_id;

  RETURN pgv.toast(pgv.t('ledger.toast_line_deleted'))
    || pgv.redirect(pgv.call_ref('get_entry', jsonb_build_object('p_id', v_entry_id)));
END;
$function$;
COMMENT ON FUNCTION ledger.post_line_delete(jsonb) IS 'Supprimer une ligne d''écriture brouillon';

GRANT USAGE ON SCHEMA ledger TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA ledger TO web_anon;

-- Schema: ledger_ut
CREATE SCHEMA IF NOT EXISTS ledger_ut;

CREATE OR REPLACE FUNCTION ledger_ut.test_account_balance()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_acc_512 integer;
  v_acc_706 integer;
  v_html text;
BEGIN
  -- Cleanup: unpost first, then delete
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  SELECT id INTO v_acc_512 FROM ledger.account WHERE code = '512';
  SELECT id INTO v_acc_706 FROM ledger.account WHERE code = '706';

  -- Create and post a balanced entry
  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES (CURRENT_DATE, 'TEST-BAL', 'Test balance')
  RETURNING id INTO v_entry_id;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit)
  VALUES (v_entry_id, v_acc_512, 1000, 0),
         (v_entry_id, v_acc_706, 0, 1000);

  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  -- Verify via get_account page
  v_html := ledger.get_account(v_acc_512);
  RETURN NEXT ok(v_html LIKE '%1 000.00%', 'Banque (asset) affiche solde 1 000.00');

  v_html := ledger.get_account(v_acc_706);
  RETURN NEXT ok(v_html LIKE '%1 000.00%', 'Prestations (revenue) affiche solde 1 000.00');

  v_html := ledger.get_index();
  RETURN NEXT ok(v_html LIKE '%1 000.00%', 'Dashboard affiche solde banque');

  -- Cleanup
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_account_balance() IS 'Test soldes corrects selon type (débiteur/créditeur) via posted entries';

CREATE OR REPLACE FUNCTION ledger_ut.test_balance()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_entry_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  -- Create a posted entry
  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES ('2026-01-15', 'BAL-TEST', 'Test balance')
  RETURNING id INTO v_entry_id;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '411'), 1200.00, 0, 'Client'),
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '706'), 0, 1200.00, 'Prestation');
  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  v_html := ledger.get_balance(2026);
  RETURN NEXT ok(length(v_html) > 100, 'get_balance() retourne du HTML substantiel');
  RETURN NEXT ok(v_html LIKE '%411%', 'Balance contient compte 411');
  RETURN NEXT ok(v_html LIKE '%706%', 'Balance contient compte 706');
  RETURN NEXT ok(v_html LIKE '%quilibre OK%', 'Balance affiche Équilibre OK');

  -- Cleanup
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_balance() IS 'Test balance de vérification : total débit = total crédit';

CREATE OR REPLACE FUNCTION ledger_ut.test_entry_balanced()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-EQ', 'description', 'Test équilibre'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '512', 'debit', 100, 'credit', 0
  ));

  RETURN NEXT throws_ok(
    format('SELECT ledger.post_entry_post(''{"id":%s}''::jsonb)', v_entry_id),
    'Écriture déséquilibrée : impossible de valider'
  );

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '601', 'debit', 0, 'credit', 100
  ));

  RETURN NEXT lives_ok(
    format('SELECT ledger.post_entry_post(''{"id":%s}''::jsonb)', v_entry_id),
    'Écriture équilibrée : validation OK'
  );

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_entry_balanced() IS 'Test validation impossible si écriture déséquilibrée';

CREATE OR REPLACE FUNCTION ledger_ut.test_extourne()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry1_id integer;
  v_entry2_id integer;
  v_html text;
  v_acc_512 integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  SELECT id INTO v_acc_512 FROM ledger.account WHERE code = '512';

  -- Écriture originale : achat 601 débit 500, 512 crédit 500
  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-EXT1', 'description', 'Achat original'
  ));
  SELECT id INTO v_entry1_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry1_id, 'account_code', '601', 'debit', 500, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry1_id, 'account_code', '512', 'debit', 0, 'credit', 500
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry1_id));

  v_html := ledger.get_account(v_acc_512);
  RETURN NEXT ok(v_html LIKE '%500.00%', 'Banque affiche solde après achat');

  -- Extourne : sens inversé
  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-EXT2', 'description', 'Extourne achat'
  ));
  SELECT id INTO v_entry2_id FROM ledger.journal_entry WHERE reference = 'TEST-EXT2';

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry2_id, 'account_code', '512', 'debit', 500, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry2_id, 'account_code', '601', 'debit', 0, 'credit', 500
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry2_id));

  v_html := ledger.get_account(v_acc_512);
  RETURN NEXT ok(v_html LIKE '%0.00%', 'Après extourne, solde banque = 0');

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_extourne() IS 'Test écriture d''extourne annule bien le solde';

CREATE OR REPLACE FUNCTION ledger_ut.test_from_expense()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_entry_id integer;
  v_line_count integer;
  v_total_debit numeric;
  v_total_credit numeric;
  v_ref text;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  -- Create expense entry: 100 HT + 20 TVA = 120 TTC, catégorie déplacements
  v_result := ledger.post_from_expense(jsonb_build_object(
    'note_id', 999,
    'montant_ht', 100,
    'tva', 20,
    'code_comptable', '625',
    'libelle', 'Déplacement chantier Bordeaux'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'Écriture NDF créée avec succès');

  SELECT id, reference INTO v_entry_id, v_ref FROM ledger.journal_entry WHERE expense_note_id = 999;
  RETURN NEXT ok(v_entry_id IS NOT NULL, 'Écriture liée à expense_note_id=999');
  RETURN NEXT ok(v_ref = 'NDF-999', 'Référence = NDF-999');

  SELECT count(*) INTO v_line_count FROM ledger.entry_line WHERE journal_entry_id = v_entry_id;
  RETURN NEXT ok(v_line_count = 3, 'Écriture a 3 lignes (charge + TVA + personnel)');

  SELECT sum(debit), sum(credit) INTO v_total_debit, v_total_credit
    FROM ledger.entry_line WHERE journal_entry_id = v_entry_id;
  RETURN NEXT ok(v_total_debit = v_total_credit, 'Écriture équilibrée : débit = crédit');
  RETURN NEXT ok(v_total_debit = 120, 'Total = 120 TTC (100 HT + 20 TVA)');

  -- Doublon interdit
  v_result := ledger.post_from_expense(jsonb_build_object(
    'note_id', 999, 'montant_ht', 50
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'Doublon expense_note_id interdit');

  -- Sans TVA = 2 lignes
  v_result := ledger.post_from_expense(jsonb_build_object(
    'note_id', 1000,
    'montant_ht', 50,
    'code_comptable', '625',
    'libelle', 'Péage autoroute'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry WHERE expense_note_id = 1000;
  SELECT count(*) INTO v_line_count FROM ledger.entry_line WHERE journal_entry_id = v_entry_id;
  RETURN NEXT ok(v_line_count = 2, 'Sans TVA = 2 lignes (charge + personnel)');

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_from_expense() IS 'Test écriture comptable depuis note de frais (NDF)';

CREATE OR REPLACE FUNCTION ledger_ut.test_from_facture()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_facture_id integer;
  v_entry_id integer;
  v_line_count integer;
  v_total_debit numeric;
  v_total_credit numeric;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  SELECT f.id INTO v_facture_id
    FROM quote.facture f
    JOIN quote.ligne l ON l.facture_id = f.id
   GROUP BY f.id
   HAVING count(*) > 0
   LIMIT 1;

  IF v_facture_id IS NULL THEN
    RETURN NEXT skip('Aucune facture avec lignes dans quote — test ignoré');
    RETURN;
  END IF;

  PERFORM ledger.post_from_facture(jsonb_build_object('facture_id', v_facture_id));

  SELECT id INTO v_entry_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;

  SELECT count(*), sum(debit), sum(credit)
    INTO v_line_count, v_total_debit, v_total_credit
    FROM ledger.entry_line WHERE journal_entry_id = v_entry_id;

  RETURN NEXT ok(v_line_count >= 2, 'Écriture facture a >= 2 lignes (a ' || v_line_count || ')');
  RETURN NEXT is(v_total_debit, v_total_credit, 'Écriture facture équilibrée : débit = crédit');

  RETURN NEXT ok(
    EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_entry_id AND reference LIKE 'FAC-%'),
    'Référence commence par FAC-'
  );

  RETURN NEXT ok(
    EXISTS (SELECT 1 FROM ledger.entry_line el JOIN ledger.account a ON a.id = el.account_id
            WHERE el.journal_entry_id = v_entry_id AND a.code = '411' AND el.debit > 0),
    'Ligne 411 Clients en débit'
  );
  RETURN NEXT ok(
    EXISTS (SELECT 1 FROM ledger.entry_line el JOIN ledger.account a ON a.id = el.account_id
            WHERE el.journal_entry_id = v_entry_id AND a.code = '706' AND el.credit > 0),
    'Ligne 706 Prestations en crédit'
  );

  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_from_facture() IS 'Test écriture générée depuis facture quote correctement ventilée';

CREATE OR REPLACE FUNCTION ledger_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_entry_id integer;
  v_acc_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
  DELETE FROM ledger.exercice;

  v_html := ledger.get_index();
  RETURN NEXT ok(length(v_html) > 50, 'get_index() retourne du HTML');

  v_html := ledger.get_entries();
  RETURN NEXT ok(length(v_html) > 50, 'get_entries() retourne du HTML');

  v_html := ledger.get_accounts();
  RETURN NEXT ok(length(v_html) > 50, 'get_accounts() retourne du HTML');

  v_html := ledger.get_entry_form();
  RETURN NEXT ok(length(v_html) > 50, 'get_entry_form() retourne du HTML');

  v_html := ledger.get_tva();
  RETURN NEXT ok(length(v_html) > 50, 'get_tva() retourne du HTML');

  v_html := ledger.get_bilan();
  RETURN NEXT ok(length(v_html) > 50, 'get_bilan() retourne du HTML');

  v_html := ledger.get_balance();
  RETURN NEXT ok(length(v_html) > 50, 'get_balance() retourne du HTML');

  v_html := ledger.get_exercice();
  RETURN NEXT ok(length(v_html) > 50, 'get_exercice() retourne du HTML');

  SELECT id INTO v_acc_id FROM ledger.account LIMIT 1;
  v_html := ledger.get_account(v_acc_id);
  RETURN NEXT ok(length(v_html) > 50, 'get_account(id) retourne du HTML');

  v_html := ledger.get_grand_livre(jsonb_build_object('p_account_id', v_acc_id));
  RETURN NEXT ok(length(v_html) > 50, 'get_grand_livre(id) retourne du HTML');

  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-PAGE', 'description', 'Test pages'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;
  v_html := ledger.get_entry(v_entry_id);
  RETURN NEXT ok(length(v_html) > 50, 'get_entry(id) retourne du HTML');

  v_html := ledger.get_entry_form(v_entry_id);
  RETURN NEXT ok(length(v_html) > 50, 'get_entry_form(id) retourne du HTML');

  RETURN NEXT ok(ledger.nav_items() IS NOT NULL, 'nav_items() retourne du JSON');
  RETURN NEXT ok(length(ledger.brand()) > 0, 'brand() retourne un label');

  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_pages_render() IS 'Test toutes les pages retournent du HTML non-vide';

CREATE OR REPLACE FUNCTION ledger_ut.test_post_cloture()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_result text;
  v_exercice record;
  v_total_debit numeric;
  v_total_credit numeric;
  v_clo_entry_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
  DELETE FROM ledger.exercice;

  -- Create a revenue entry in 2025
  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES ('2025-06-15', 'FAC-TEST', 'Facture test clôture')
  RETURNING id INTO v_entry_id;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '411'), 1200.00, 0, 'Client'),
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '4457'), 0, 200.00, 'TVA'),
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '706'), 0, 1000.00, 'Prestation');
  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  -- Create an expense entry in 2025
  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES ('2025-03-10', 'ACH-TEST', 'Achat test clôture')
  RETURNING id INTO v_entry_id;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '601'), 300.00, 0, 'Matériaux'),
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '512'), 0, 300.00, 'Paiement');
  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  -- Clôturer 2025
  v_result := ledger.post_cloture('{"year": 2025}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'Clôture 2025 réussie');

  -- Vérifier exercice
  SELECT * INTO v_exercice FROM ledger.exercice WHERE year = 2025;
  RETURN NEXT ok(v_exercice.closed, 'Exercice 2025 marqué clos');
  RETURN NEXT is(v_exercice.result, 700.00, 'Résultat = 1000 - 300 = 700');

  -- Vérifier écriture de clôture équilibrée
  SELECT id INTO v_clo_entry_id FROM ledger.journal_entry WHERE reference = 'CLO-2025';
  RETURN NEXT ok(v_clo_entry_id IS NOT NULL, 'Écriture CLO-2025 créée');

  SELECT sum(debit), sum(credit)
    INTO v_total_debit, v_total_credit
    FROM ledger.entry_line WHERE journal_entry_id = v_clo_entry_id;
  RETURN NEXT is(v_total_debit, v_total_credit, 'Écriture clôture équilibrée');

  -- Double clôture bloquée
  v_result := ledger.post_cloture('{"year": 2025}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%déjà clôturé%', 'Double clôture bloquée');

  -- Cleanup
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
  DELETE FROM ledger.exercice;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_post_cloture() IS 'Test clôture exercice : résultat correct, double clôture bloquée, écriture de résultat équilibrée';

CREATE OR REPLACE FUNCTION ledger_ut.test_protect_posted()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_line_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-PROT', 'description', 'Test protection'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '512', 'debit', 200, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '601', 'debit', 0, 'credit', 200
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry_id));

  SELECT id INTO v_line_id FROM ledger.entry_line WHERE journal_entry_id = v_entry_id LIMIT 1;

  RETURN NEXT throws_ok(
    format('UPDATE ledger.journal_entry SET description = ''hack'' WHERE id = %s', v_entry_id),
    'Écriture validée : modification interdite (id=' || v_entry_id || ')'
  );

  RETURN NEXT throws_ok(
    format('DELETE FROM ledger.journal_entry WHERE id = %s', v_entry_id),
    'Écriture validée : suppression interdite (id=' || v_entry_id || ')'
  );

  RETURN NEXT throws_ok(
    format('INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit) VALUES (%s, (SELECT id FROM ledger.account WHERE code = ''512''), 10, 0)', v_entry_id),
    'Écriture validée : modification des lignes interdite'
  );

  RETURN NEXT throws_ok(
    format('UPDATE ledger.entry_line SET debit = 999 WHERE id = %s', v_line_id),
    'Écriture validée : modification des lignes interdite'
  );

  RETURN NEXT throws_ok(
    format('DELETE FROM ledger.entry_line WHERE id = %s', v_line_id),
    'Écriture validée : modification des lignes interdite'
  );

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_protect_posted() IS 'Test immutabilité : UPDATE/DELETE bloqués sur écriture validée + lignes';

CREATE OR REPLACE FUNCTION ledger_ut.test_tva()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_html text;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  -- Vente avec TVA collectée
  PERFORM ledger.post_entry_save(jsonb_build_object(
    'entry_date', CURRENT_DATE, 'reference', 'TEST-TVA1', 'description', 'Vente prestation'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry WHERE reference = 'TEST-TVA1';

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '411', 'debit', 120, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '4457', 'debit', 0, 'credit', 20
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '706', 'debit', 0, 'credit', 100
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry_id));

  -- Achat avec TVA déductible
  PERFORM ledger.post_entry_save(jsonb_build_object(
    'entry_date', CURRENT_DATE, 'reference', 'TEST-TVA2', 'description', 'Achat matériaux'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry WHERE reference = 'TEST-TVA2';

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '601', 'debit', 50, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '4456', 'debit', 10, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '512', 'debit', 0, 'credit', 60
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry_id));

  v_html := ledger.get_tva(jsonb_build_object('p_year', extract(year FROM CURRENT_DATE)::integer, 'p_quarter', extract(quarter FROM CURRENT_DATE)::integer));
  RETURN NEXT ok(v_html LIKE '%20.00%', 'TVA collectée = 20.00');
  RETURN NEXT ok(v_html LIKE '%10.00%', 'TVA déductible = 10.00');
  RETURN NEXT ok(v_html LIKE '%reverser%', 'TVA à reverser (solde positif)');

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_tva() IS 'Test déclaration TVA = 4457 - 4456';

GRANT USAGE ON SCHEMA ledger_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA ledger_ut TO web_anon;

-- Schema: ledger_qa
CREATE SCHEMA IF NOT EXISTS ledger_qa;

CREATE OR REPLACE FUNCTION ledger_qa.clean()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
    DELETE FROM ledger.entry_line;
    DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_qa.clean() IS 'Nettoie les données démo du schema ledger';

CREATE OR REPLACE FUNCTION ledger_qa.seed()
