        (v_entry_id, (SELECT id FROM ledger.account WHERE code = '4457'), 0, 500.00, 'TVA collectée 20%'),
        (v_entry_id, (SELECT id FROM ledger.account WHERE code = '706'), 0, 2500.00, 'Pose carrelage');
